#!/bin/bash

# Configuration
# API_KEY="YOUR_SIGNALOID_API_KEY"
# TASK_ID="YOUR_TASK_ID"
VARIABLE_NAME="final_value" # The name of the variable in your C code
BASE_URL="https://api.signaloid.io"

# 1. POST request to initiate the plot generation
# The API returns a 'presignedURL' which we then use to download the file
echo "Requesting plot for variable: $VARIABLE_NAME..."

PLOT_RESPONSE=$(curl -s -X POST "$BASE_URL/plot" \
    -H "Authorization: $API_KEY" \
    -H "Content-Type: application/json" \
    -d "{
        \"payload\": \"\",
        }")
echo "$PLOT_RESPONSE"
# 2. Extract the presignedURL using python3
PLOT_URL=$(echo "$PLOT_RESPONSE" | python3 -c "import sys, json; print(json.load(sys.stdin)['presignedURL'])")

if [ -z "$PLOT_URL" ] || [ "$PLOT_URL" == "None" ]; then
    echo "Error: Could not retrieve plot URL. Check your TaskID and Variable name."
    exit 1
fi

# 3. Download the plot image
# IMPORTANT: Do NOT send the Authorization header for this second request
echo "Plot generated. Downloading..."
curl -s -L "$PLOT_URL" -o plot_output.pdf

echo "Success! Plot saved as plot_output.pdf"